import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, Tag, Eye, Edit2, Check, X, Calendar, Layers
} from 'lucide-react';

// --- ESTILOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem', background: '#f8fafc', borderBottom: '1px solid #e2e8f0' };
const tdCell = { padding: '10px', borderBottom: '1px solid #f1f5f9' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', background: 'transparent', fontSize: '0.9rem' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const editInput = { width: '100%', padding: '8px', borderRadius: '8px', border: '1px solid #e2e8f0', marginBottom: '5px', fontSize: '0.85rem', outline: 'none' };

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  // --- ESTADOS ---
  const filaInicial = () => ({ id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null });
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  
  // Estados para CRUD Individual
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  // --- CARGA DE DATOS (READ) ---
  const cargarPublicados = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) { console.error("Error al cargar", e); }
  }, [API_URL, localId]);

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(err => console.log(err));
  }, [cargarPublicados]);

  // --- LÓGICA DE MATCH DE FOTOS ---
  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.toLowerCase().includes(p)));
  }, [galeria]);

  // --- MANEJO DE TABLA DE CARGA ---
  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    const nuevas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0] || '';
      return { 
        ...filaInicial(), 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: celdas[1] || '', 
        precioViejo: celdas[2] || '', 
        stock: celdas[3] || 0, 
        categoria: celdas[4] || 'Almacén', 
        fotoSugerida: buscarMatch(nombre) 
      };
    });
    setFilas(nuevas);
  };

  const actualizarFilaCarga = (id, campo, valor) => {
    setFilas(prev => prev.map(f => {
      if (f.id === id) {
        const item = { ...f, [campo]: valor };
        if (campo === 'producto') item.fotoSugerida = buscarMatch(valor);
        return item;
      }
      return f;
    }));
  };

  // --- ACCIONES CRUD (CREATE, UPDATE, DELETE) ---
  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Define fechas de validez");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          ...f, local: localId, publicado: true, 
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          fechaInicioOferta: fechas.inicio, fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      setFilas([filaInicial()]);
      cargarPublicados();
      alert("¡Publicación masiva exitosa!");
    } catch (e) { alert("Error al publicar"); } finally { setCargando(false); }
  };

  const guardarEdicionIndividual = async () => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${editandoId}`, tempData);
      setEditandoId(null);
      cargarPublicados();
    } catch (e) { alert("Error al actualizar"); }
  };

  const eliminarIndividual = async (id) => {
    if (!window.confirm("¿Eliminar este producto permanentemente?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarPublicados();
    } catch (e) { alert("Error al eliminar"); }
  };

  return (
    <div style={containerStyle}>
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <button style={{...btnNuevaSucursalCustom, background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22'}}>
          <Database size={16}/> Galería Maestra
        </button>
      </div>

      <div style={{marginBottom: '30px'}}>
        <h1 style={sidebarTitle}><Tag color="#e67e22"/> Gestión de Productos y Ofertas</h1>
        <p style={{color: '#64748b', fontSize: '0.9rem'}}>Carga masiva por Excel o edición individual de lo publicado.</p>
      </div>

      {/* BLOQUE 1: CARGA MASIVA */}
      <div style={tableWrapper} onPaste={handlePaste}>
        <table style={mainTable}>
          <thead>
            <tr>
              <th style={thCell}>Foto</th><th style={thCell}>Producto</th><th style={thCell}>P. Nuevo</th>
              <th style={thCell}>P. Viejo</th><th style={thCell}>Stock</th><th style={thCell}>Categoría</th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id}>
                <td style={tdCell}>{f.fotoSugerida ? <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_40,h_40,c_fill/v1/${f.fotoSugerida.publicId}`} style={{borderRadius:'6px'}} alt="p"/> : <ImageIcon color="#cbd5e1" size={20}/>}</td>
                <td style={tdCell}><input style={inputTable} placeholder="Producto..." value={f.producto} onChange={e => actualizarFilaCarga(f.id, 'producto', e.target.value)}/></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioNuevo} onChange={e => actualizarFilaCarga(f.id, 'precioNuevo', e.target.value)}/></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioViejo} onChange={e => actualizarFilaCarga(f.id, 'precioViejo', e.target.value)}/></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.stock} onChange={e => actualizarFilaCarga(f.id, 'stock', e.target.value)}/></td>
                <td style={tdCell}>
                  <select style={{border:'none', background:'transparent', fontSize:'0.85rem'}} value={f.categoria} onChange={e => actualizarFilaCarga(f.id, 'categoria', e.target.value)}>
                    <option value="Almacén">Almacén</option><option value="Carnicería">Carnicería</option><option value="Lácteos">Lácteos</option><option value="Bebidas">Bebidas</option>
                  </select>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{padding: '20px', background: '#f8fafc', display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
          <div style={{display:'flex', gap:'15px'}}>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #ddd'}}/>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #ddd'}}/>
          </div>
          <button onClick={publicarTodo} disabled={cargando} style={btnNuevaSucursalCustom}>
            {cargando ? <Loader2 className="animate-spin"/> : <Sparkles/>} Publicar Todo
          </button>
        </div>
      </div>

      {/* BLOQUE 2: CRUD INDIVIDUAL DE LO PUBLICADO */}
      <h2 style={{...sidebarTitle, fontSize: '1.4rem', marginBottom: '20px'}}><Eye color="#1e293b"/> Productos Publicados (CRUD)</h2>
      <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px'}}>
        {publicados.map(p => (
          <div key={p._id} style={{background: 'white', padding: '20px', borderRadius: '20px', border: editandoId === p._id ? '2px solid #3b82f6' : '1px solid #e2e8f0', position: 'relative'}}>
            <div style={{position:'absolute', top:'10px', right:'10px', display:'flex', gap:'5px'}}>
              {editandoId === p._id ? (
                <>
                  <button onClick={guardarEdicionIndividual} style={{background:'#dcfce7', color:'#16a34a', border:'none', borderRadius:'50%', width:'32px', height:'32px', cursor:'pointer'}}><Check size={16}/></button>
                  <button onClick={() => setEditandoId(null)} style={{background:'#f1f5f9', color:'#64748b', border:'none', borderRadius:'50%', width:'32px', height:'32px', cursor:'pointer'}}><X size={16}/></button>
                </>
              ) : (
                <>
                  <button onClick={() => { setEditandoId(p._id); setTempData(p); }} style={{background:'#eff6ff', color:'#3b82f6', border:'none', borderRadius:'50%', width:'32px', height:'32px', cursor:'pointer'}}><Edit2 size={16}/></button>
                  <button onClick={() => eliminarIndividual(p._id)} style={{background:'#fee2e2', color:'#ef4444', border:'none', borderRadius:'50%', width:'32px', height:'32px', cursor:'pointer'}}><Trash size={16}/></button>
                </>
              )}
            </div>

            <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_300,h_200,c_fill/v1/${p.publicId}`} style={{width:'100%', height:'120px', objectFit:'cover', borderRadius:'12px', marginBottom:'15px'}} alt={p.producto}/>
            
            {editandoId === p._id ? (
              <div>
                <input style={editInput} value={tempData.producto} onChange={e => setTempData({...tempData, producto: e.target.value})}/>
                <div style={{display:'flex', gap:'5px'}}>
                  <input style={editInput} type="number" value={tempData.precioNuevo} onChange={e => setTempData({...tempData, precioNuevo: e.target.value})}/>
                  <input style={editInput} type="number" value={tempData.precioViejo} onChange={e => setTempData({...tempData, precioViejo: e.target.value})}/>
                </div>
                <input style={editInput} type="number" value={tempData.stock} onChange={e => setTempData({...tempData, stock: e.target.value})}/>
                <select style={editInput} value={tempData.categoria} onChange={e => setTempData({...tempData, categoria: e.target.value})}>
                  <option value="Almacén">Almacén</option><option value="Carnicería">Carnicería</option><option value="Lácteos">Lácteos</option>
                </select>
              </div>
            ) : (
              <>
                <div style={{display:'flex', alignItems:'center', gap:'8px', marginBottom:'5px'}}>
                  <span style={{fontSize:'0.65rem', background:'#f1f5f9', padding:'2px 8px', borderRadius:'10px', fontWeight:'bold', color:'#64748b'}}>{p.categoria}</span>
                </div>
                <h4 style={{margin: '0', color: '#1e293b'}}>{p.producto}</h4>
                <div style={{display:'flex', gap:'10px', alignItems:'baseline', marginTop:'10px'}}>
                  <span style={{fontWeight:'bold', color:'#e67e22', fontSize:'1.2rem'}}>${p.precioNuevo}</span>
                  <span style={{textDecoration:'line-through', color:'#94a3b8', fontSize:'0.85rem'}}>${p.precioViejo}</span>
                </div>
                <div style={{marginTop:'10px', fontSize:'0.8rem', color:'#64748b', display:'flex', justifyContent:'space-between'}}>
                  <span>Stock: <strong>{p.stock}</strong></span>
                  <span><Calendar size={12}/> {new Date(p.fechaFinOferta).toLocaleDateString()}</span>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default GestionOfertas;
